  function applyHorizonShell(){var body=document.body,html=document.documentElement,app=document.querySelector('.app'),side=app&&app.querySelector(':scope>aside'),main=app&&app.querySelector(':scope>main'),mark=side&&side.querySelector('.mark');if(!body||!app)return;if(!desktop()){html.classList.remove('hzDesktop');body.classList.remove('hzDesktop');app.classList.remove('hzAppShell');if(side)side.classList.remove('hzSidebar');if(main)main.classList.remove('hzWorkspace');if(mark&&mark.dataset.hzOriginal){mark.innerHTML=mark.dataset.hzOriginal;delete mark.dataset.hzApplied;}document.querySelectorAll('aside .nav button[data-desktop-nav]>span').forEach(function(span){if(span.dataset.hzOriginal){span.innerHTML=span.dataset.hzOriginal;delete span.dataset.hzApplied;}});return;}html.classList.add('hzDesktop');body.classList.add('hzDesktop');app.classList.add('hzAppShell');if(side)side.classList.add('hzSidebar');if(main)main.classList.add('hzWorkspace');if(mark&&!mark.dataset.hzApplied){mark.dataset.hzOriginal=mark.innerHTML;mark.innerHTML=hzIcon('brand');mark.dataset.hzApplied='1';}document.querySelectorAll('aside .nav button[data-desktop-nav]').forEach(function(button){var span=button.querySelector(':scope>span'),name=button.dataset.desktopNav;if(!span)return;if(!span.dataset.hzOriginal)span.dataset.hzOriginal=span.innerHTML;span.innerHTML=hzIcon(name);span.dataset.hzApplied='1';});}
